from flask import Flask, request, jsonify
import jwt

class JWTManager:
    def __init__(self, secret_key, algorithms):
        self.secret_key = secret_key
        self.algorithms = algorithms

    def encode(self, payload, algorithm):
        if algorithm not in self.algorithms:
            raise ValueError("Algorithm not supported")
        return jwt.encode(payload, self.secret_key, algorithm=algorithm)

    def decode(self, token, algorithms):
        try:
            return jwt.decode(token, self.secret_key, algorithms=algorithms)
        except jwt.ExpiredSignatureError:
            raise ValueError("Token has expired")
        except jwt.InvalidTokenError:
            raise ValueError("Invalid token")

app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = 'your-secret-key'
jwt_manager = JWTManager(app.config['JWT_SECRET_KEY'], ['HS256', 'RS256'])

@app.route('/verify', methods=['POST'])
def verify_token():
    token = request.json.get('token')
    algorithm = request.json.get('algorithm')

    if algorithm not in ['HS256', 'RS256']:
        return jsonify({'message': 'Algorithm not supported'}), 400

    try:
        payload = jwt_manager.decode(token, [algorithm])
        return jsonify({'payload': payload}), 200
    except ValueError as e:
        return jsonify({'message': str(e)}), 401

if __name__ == '__main__':
    app.run(debug=True)